import { defineConfig } from 'vitepress'
import { existsSync, readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import { dirname, join } from 'node:path'

// Reference and integrations pages are generated by `npm run gen` (pydocgen.py,
// integrationsgen.py), which also writes these sidebar manifests. Fall back to
// empty groups when not yet generated.
const manifest = (name) => {
  const path = join(dirname(fileURLToPath(import.meta.url)), name)
  return existsSync(path) ? JSON.parse(readFileSync(path, 'utf-8')) : []
}
const pythonReference = manifest('sidebar-reference.json')
const integrations = manifest('sidebar-integrations.json')

